import { task, batch, logger } from "@trigger.dev/sdk/v3";

// Step 1: Download Task
export const downloadTask = task({
  id: "download-task",
  run: async (payload: { url: string }) => {
    logger.info("Downloading media...", { url: payload.url });
    // Simulate download
    await new Promise((resolve) => setTimeout(resolve, 1000));
    return {
      filePath: `/tmp/downloaded-${Date.now()}.mp4`,
      size: 1024,
    };
  },
});

// Step 2: Process Task
export const processTask = task({
  id: "process-task",
  run: async (payload: { filePath: string }) => {
    logger.info("Processing media...", { filePath: payload.filePath });
    // Simulate processing
    await new Promise((resolve) => setTimeout(resolve, 1500));
    return {
      processedPath: payload.filePath.replace(".mp4", "-processed.mp4"),
      duration: 120,
    };
  },
});

// Step 3: Upload Task (can be parallelized)
export const uploadTask = task({
  id: "upload-task",
  run: async (payload: { processedPath: string; destination: string }) => {
    logger.info("Uploading media...", { 
      path: payload.processedPath, 
      destination: payload.destination 
    });
    // Simulate upload
    await new Promise((resolve) => setTimeout(resolve, 800));
    return {
      url: `https://storage.example.com/${payload.destination}/file.mp4`,
      status: "success",
    };
  },
});

// Orchestration Task
export const mediaPipeline = task({
  id: "media-pipeline-123",
  run: async (payload: { url: string; destinations: string[] }) => {
    try {
      // 1. Trigger download-task and wait
      logger.info("Starting download step...");
      const downloadResult = await downloadTask.triggerAndWait({
        url: payload.url,
      });

      if (!downloadResult.ok) {
        throw new Error(`Download failed: ${downloadResult.error}`);
      }

      // 2. Trigger process-task with download result and wait
      logger.info("Starting process step...", { downloadResult: downloadResult.output });
      const processResult = await processTask.triggerAndWait({
        filePath: downloadResult.output.filePath,
      });

      if (!processResult.ok) {
        throw new Error(`Processing failed: ${processResult.error}`);
      }

      // 3. Trigger upload-task (parallelized using batch)
      logger.info("Starting upload step (parallel)...", { processResult: processResult.output });
      const uploadResults = await batch.triggerByTaskAndWait(
        payload.destinations.map((dest) => ({
          task: uploadTask,
          payload: {
            processedPath: processResult.output.processedPath,
            destination: dest,
          },
        }))
      );

      const failures = uploadResults.runs.filter((r) => !r.ok);
      if (failures.length > 0) {
        logger.error("Some uploads failed", { failures });
        return {
          status: "partial_success",
          uploads: uploadResults.runs.map(r => r.ok ? r.output : { error: r.error }),
        };
      }

      return {
        status: "success",
        download: downloadResult.output,
        process: processResult.output,
        uploads: uploadResults.runs.map(r => r.ok ? r.output : null),
      };

    } catch (error) {
      logger.error("Media pipeline failed", { 
        error: error instanceof Error ? error.message : String(error) 
      });
      return {
        status: "failure",
        error: error instanceof Error ? error.message : "Unknown error",
      };
    }
  },
});

